#include <iostream>
#include <vector>
using namespace std;

void bf(const string &s){
  for(int i=0,b=0;i<s.size();++i){
    if(s[i]=='[')++b;if(s[i]==']')--b;
    if(b<0)return;
  }
  vector<short> dat(30000);
  for(int i=0,ptr=0;i<s.size();++i){
    if(s[i]=='+'||s[i]=='-') dat[ptr]=(dat[ptr]+((s[i]=='+')?1:-1)+0x100)&0xff;
    if(s[i]=='<'){--ptr;if(ptr<0)return;}
    if(s[i]=='>'){++ptr;if(ptr>=dat.size())dat.resize(dat.size()+dat.size()/2);}
    if(s[i]=='['){
      if(!dat[ptr]){
        for(int j=i+1,b=0;j<s.size();++j){
        	if(b==0&&s[j]==']'){i=j;break;}
        	if(s[j]=='[')++b;if(s[j]==']')--b;
        }
      }
    }
    if(s[i]==']'){
      if(dat[ptr]){
        for(int j=i-1,b=0;j>=0;--j){
        	if(b==0&&s[j]=='['){i=j;break;}
        	if(s[j]==']')++b;if(s[j]=='[')--b;
        }
      }
    }
    if(s[i]=='.') cout<<(char)dat[ptr];
  }
}
